function firstJson(nodeName) {
  try {
    return $(nodeName).first().json || {};
  } catch (e) {
    return {};
  }
}

function numberValue(value) {
  if (value === null || value === undefined || value === '') return 0;
  const number = Number(value);
  return Number.isFinite(number) ? number : 0;
}

function pctChange(current, previous) {
  if (previous === 0 && current === 0) return 0;
  if (previous === 0) return 100;
  return Number((((current - previous) / previous) * 100).toFixed(2));
}

function completionRate(metrics) {
  return metrics.tasks.created === 0
    ? 0
    : Number(((metrics.tasks.completed / metrics.tasks.created) * 100).toFixed(2));
}

function errorRate(metrics) {
  const operationalVolume = metrics.emails.processed + metrics.tasks.created + metrics.ai_usage.total_calls;
  return operationalVolume === 0
    ? 0
    : Number(((metrics.errors.count / operationalVolume) * 100).toFixed(2));
}

const now = new Date();
const reportDate = now.toISOString().slice(0, 10);
const emails = firstJson('Emails Processed');
const tasks = firstJson('Tasks Metrics');
const ai = firstJson('AI Usage');
const errors = firstJson('Errors Count');
const approvals = firstJson('Approvals Status');
const previous = firstJson('Last Week Comparison');

const thisWeek = {
  report_date: reportDate,
  period: {
    label: 'last_7_days',
    generated_at: now.toISOString()
  },
  emails: {
    processed: numberValue(emails.count)
  },
  tasks: {
    created: numberValue(tasks.created),
    completed: numberValue(tasks.completed),
    overdue: numberValue(tasks.overdue)
  },
  ai_usage: {
    total_calls: numberValue(ai.total_calls),
    total_input_tokens: numberValue(ai.total_input_tokens),
    total_output_tokens: numberValue(ai.total_output_tokens),
    total_cost: numberValue(ai.total_cost),
    avg_latency_ms: Math.round(numberValue(ai.avg_latency))
  },
  errors: {
    count: numberValue(errors.count)
  },
  approvals: {
    pending: numberValue(approvals.pending),
    approved: numberValue(approvals.approved)
  }
};

const lastWeek = {
  period: {
    label: 'previous_7_days'
  },
  emails: {
    processed: numberValue(previous.emails_processed)
  },
  tasks: {
    created: numberValue(previous.tasks_created),
    completed: numberValue(previous.tasks_completed),
    overdue: numberValue(previous.tasks_overdue)
  },
  ai_usage: {
    total_calls: numberValue(previous.ai_total_calls),
    total_input_tokens: numberValue(previous.ai_total_input_tokens),
    total_output_tokens: numberValue(previous.ai_total_output_tokens),
    total_cost: numberValue(previous.ai_total_cost),
    avg_latency_ms: Math.round(numberValue(previous.ai_avg_latency))
  },
  errors: {
    count: numberValue(previous.errors_count)
  },
  approvals: {
    pending: numberValue(previous.approvals_pending),
    approved: numberValue(previous.approvals_approved)
  }
};

const trends = {
  emails_change_pct: pctChange(thisWeek.emails.processed, lastWeek.emails.processed),
  tasks_completion_rate_change: Number((completionRate(thisWeek) - completionRate(lastWeek)).toFixed(2)),
  error_rate_change: Number((errorRate(thisWeek) - errorRate(lastWeek)).toFixed(2)),
  ai_cost_change: pctChange(thisWeek.ai_usage.total_cost, lastWeek.ai_usage.total_cost),
  this_week_completion_rate: completionRate(thisWeek),
  last_week_completion_rate: completionRate(lastWeek),
  this_week_error_rate: errorRate(thisWeek),
  last_week_error_rate: errorRate(lastWeek)
};

const metrics = {
  this_week: thisWeek,
  last_week: lastWeek,
  trends
};

const metricsTable = [
  `Weekly Operations Digest - ${reportDate}`,
  '',
  'This Week',
  `Emails processed: ${thisWeek.emails.processed}`,
  `Tasks created: ${thisWeek.tasks.created}`,
  `Tasks completed: ${thisWeek.tasks.completed}`,
  `Open overdue tasks: ${thisWeek.tasks.overdue}`,
  `AI calls: ${thisWeek.ai_usage.total_calls}`,
  `AI cost: $${thisWeek.ai_usage.total_cost.toFixed(4)}`,
  `Errors: ${thisWeek.errors.count}`,
  `Approvals pending: ${thisWeek.approvals.pending}`,
  `Approvals approved: ${thisWeek.approvals.approved}`,
  '',
  'Trends vs Previous Week',
  `Emails change: ${trends.emails_change_pct}%`,
  `Task completion rate change: ${trends.tasks_completion_rate_change} points`,
  `Error rate change: ${trends.error_rate_change} points`,
  `AI cost change: ${trends.ai_cost_change}%`
].join('\n');

return [{
  json: {
    date: reportDate,
    metrics,
    trends,
    metrics_json: JSON.stringify(metrics, null, 2),
    metrics_table: metricsTable
  }
}];

parameters.workflowInputs:
